result.documentation:
Recognizes an unsigned 2 bytes integer

If the parameter is `nom::number::Endianness::Big`, parse a big endian u16 integer,
otherwise if `nom::number::Endianness::Little` parse a little endian u16 integer.

```rust
# use nom::{Err, error::ErrorKind, Needed, Parser};
# use nom::Needed::Size;
use nom::number::u16;

let be_u16 = |s| {
u16::<_, (_, ErrorKind)>(nom::number::Endianness::Big).parse(s)
};

assert_eq!(be_u16(&b"\x00\x03abcefg"[..]), Ok((&b"abcefg"[..], 0x0003)));
assert_eq!(be_u16(&b"\x01"[..]), Err(Err::Incomplete(Needed::new(1))));

let le_u16 = |s| {
u16::<_, (_, ErrorKind)>(nom::number::Endianness::Little).parse(s)
};

assert_eq!(le_u16(&b"\x00\x03abcefg"[..]), Ok((&b"abcefg"[..], 0x0300)));
assert_eq!(le_u16(&b"\x01"[..]), Err(Err::Incomplete(Needed::new(1))));
```
[inline]

result.signature:
pub fn u16<I, E: ParseError<I>>(
  endian: crate::number::Endianness,
) -> impl Parser<I, Output = u16, Error = E>
where
  I: Input<Item = u8>,
{
  match endian {
    crate::number::Endianness::Big => Either::Left(be_u16()),
    crate::number::Endianness::Little => Either::Right(le_u16()),
    #[cfg(target_endian = "big")]
    crate::number::Endianness::Native => Either::Left(be_u16()),
    #[cfg(target_endian = "little")]
    crate::number::Endianness::Native => Either::Right(le_u16()),
  }
}

result.documentation:
Recognizes a pattern.

The input data will be compared to the tag combinator's argument and will return the part of
the input that matches the argument.
# Example
```rust
# use nom::{Err, error::{Error, ErrorKind}, Needed, IResult};
use nom::bytes::streaming::tag;

fn parser(s: &str) -> IResult<&str, &str> {
tag("Hello")(s)
}

assert_eq!(parser("Hello, World!"), Ok((", World!", "Hello")));
assert_eq!(parser("Something"), Err(Err::Error(Error::new("Something", ErrorKind::Tag))));
assert_eq!(parser("S"), Err(Err::Error(Error::new("S", ErrorKind::Tag))));
assert_eq!(parser("H"), Err(Err::Incomplete(Needed::new(4))));
```

result.signature:
pub fn tag<T, I, Error: ParseError<I>>(tag: T) -> impl Parser<I, Output = I, Error = Error>
where
  I: Input + Compare<T>,
  T: InputLength + Clone,
{
  Tag {
    tag,
    e: PhantomData,
  }
}

fn process<OM: OutputMode>(&mut self, i: I) -> crate::PResult<OM, I, Self::Output, Self::Error> {
    let tag_len = self.tag.input_len();
    let t = self.tag.clone();

    match i.compare(t) {
      CompareResult::Ok => Ok((i.take_from(tag_len), OM::Output::bind(|| i.take(tag_len)))),
      CompareResult::Incomplete => {
        if OM::Incomplete::is_streaming() {
          Err(Err::Incomplete(Needed::new(tag_len - i.input_len())))
        } else {
          Err(Err::Error(OM::Error::bind(|| {
            let e: ErrorKind = ErrorKind::Tag;
            Error::from_error_kind(i, e)
          })))
        }
      }
      CompareResult::Error => Err(Err::Error(OM::Error::bind(|| {
        let e: ErrorKind = ErrorKind::Tag;
        Error::from_error_kind(i, e)
      }))),
    }
  }

result.documentation:
Recognizes a case insensitive pattern.

The input data will be compared to the tag combinator's argument and will return the part of
the input that matches the argument with no regard to case.
# Example
```rust
# use nom::{Err, error::{Error, ErrorKind}, Needed, IResult};
use nom::bytes::streaming::tag_no_case;

fn parser(s: &str) -> IResult<&str, &str> {
tag_no_case("hello")(s)
}

assert_eq!(parser("Hello, World!"), Ok((", World!", "Hello")));
assert_eq!(parser("hello, World!"), Ok((", World!", "hello")));
assert_eq!(parser("HeLlO, World!"), Ok((", World!", "HeLlO")));
assert_eq!(parser("Something"), Err(Err::Error(Error::new("Something", ErrorKind::Tag))));
assert_eq!(parser(""), Err(Err::Incomplete(Needed::new(5))));
```

result.signature:
pub fn tag_no_case<T, I, Error: ParseError<I>>(tag: T) -> impl Parser<I, Output = I, Error = Error>
where
  I: Input + Compare<T>,
  T: InputLength + Clone,
{
  TagNoCase {
    tag,
    e: PhantomData,
  }
}

fn process<OM: OutputMode>(&mut self, i: I) -> crate::PResult<OM, I, Self::Output, Self::Error> {
    let tag_len = self.tag.input_len();
    let t = self.tag.clone();

    match i.compare_no_case(t) {
      CompareResult::Ok => Ok((i.take_from(tag_len), OM::Output::bind(|| i.take(tag_len)))),
      CompareResult::Incomplete => {
        if OM::Incomplete::is_streaming() {
          Err(Err::Incomplete(Needed::new(tag_len - i.input_len())))
        } else {
          Err(Err::Error(OM::Error::bind(|| {
            let e: ErrorKind = ErrorKind::Tag;
            Error::from_error_kind(i, e)
          })))
        }
      }
      CompareResult::Error => Err(Err::Error(OM::Error::bind(|| {
        let e: ErrorKind = ErrorKind::Tag;
        Error::from_error_kind(i, e)
      }))),
    }
  }

fn process<OM: OutputMode>(&mut self, i: I) -> crate::PResult<OM, I, Self::Output, Self::Error> {
    i.split_at_position_mode::<OM, _, _>(|c| (self.predicate)(c))
  }

fn process<OM: OutputMode>(&mut self, i: I) -> crate::PResult<OM, I, Self::Output, Self::Error> {
    i.split_at_position_mode1::<OM, _, _>(|c| (self.predicate)(c), self.e)
  }

result.documentation:
Parse till certain characters are met.

The parser will return the longest slice till one of the characters of the combinator's argument are met.

It doesn't consume the matched character.

It will return a `Err::Error(("", ErrorKind::IsNot))` if the pattern wasn't met.
# Example
```rust
# use nom::{Err, error::{Error, ErrorKind}, Needed, IResult};
use nom::bytes::complete::is_not;

fn not_space(s: &str) -> IResult<&str, &str> {
is_not(" \t\r\n")(s)
}

assert_eq!(not_space("Hello, World!"), Ok((" World!", "Hello,")));
assert_eq!(not_space("Sometimes\t"), Ok(("\t", "Sometimes")));
assert_eq!(not_space("Nospace"), Ok(("", "Nospace")));
assert_eq!(not_space(""), Err(Err::Error(Error::new("", ErrorKind::IsNot))));
```

